/// Writes the `june_browser` MCP script into the managed Hermes home and returns
/// its config. `enabled` carries the stored Browser access grant, read fresh on
/// every spawn, so the rendered `june_browser` entry's `enabled` leaf follows
/// the grant. The script and its config are always written regardless of the
/// grant (only the `enabled` leaf reflects it).
async fn sync_june_browser_mcp(
    app: &AppHandle,
    hermes_command: &str,
    enabled: bool,
) -> Result<JuneBrowserMcpConfig, AppError> {
    let data_dir = crate::app_paths::app_data_dir(app)
        .map_err(|error| AppError::new("june_browser_mcp_failed", error.to_string()))?;
    let mcp_dir = data_dir.join(JUNE_CONTEXT_MCP_DIR_NAME);
    fs::create_dir_all(&mcp_dir)
        .map_err(|error| AppError::new("june_browser_mcp_failed", error.to_string()))?;
    let script_path = mcp_dir.join(JUNE_BROWSER_MCP_SCRIPT_NAME);
    fs::write(&script_path, JUNE_BROWSER_MCP_SCRIPT)
        .map_err(|error| AppError::new("june_browser_mcp_failed", error.to_string()))?;

    // While the Browser use feature flag is off, persisted routine opt-ins
    // stay dormant: no per-routine server is rendered and the broker's grant
    // table is replaced with nothing, so a dev-build opt-in cannot resurface.
    let routine_grants = if crate::experimental_settings::browser_use_enabled(app) {
        crate::commands::repositories(app)
            .await?
            .list_routine_browser_grants()
            .await?
            .into_iter()
            .map(|grant| RoutineBrowserGrant {
                job_id: grant.job_id,
                server_name: grant.server_name,
                token: grant.token,
                enabled: grant.enabled,
            })
            .collect()
    } else {
        Vec::new()
    };

    Ok(JuneBrowserMcpConfig {
        command: hermes_python_command(hermes_command),
        script_path,
        enabled,
        routine_grants,
    })
}

fn sync_june_computer_use_mcp(
    app: &AppHandle,
    hermes_command: &str,
    enabled: bool,
) -> Result<JuneComputerUseMcpConfig, AppError> {
    let data_dir = crate::app_paths::app_data_dir(app)
        .map_err(|error| AppError::new("june_computer_use_mcp_failed", error.to_string()))?;
    let mcp_dir = data_dir.join(JUNE_CONTEXT_MCP_DIR_NAME);
    fs::create_dir_all(&mcp_dir)
        .map_err(|error| AppError::new("june_computer_use_mcp_failed", error.to_string()))?;
    let script_path = mcp_dir.join(crate::computer_use::MCP_SCRIPT_NAME);
    fs::write(&script_path, crate::computer_use::MCP_SCRIPT)
        .map_err(|error| AppError::new("june_computer_use_mcp_failed", error.to_string()))?;

    Ok(JuneComputerUseMcpConfig {
        command: hermes_python_command(hermes_command),
        script_path,
        enabled,
    })
}

/// True when this connected account should back the `june_linear` read
/// server: a CONNECTED Linear workspace with at least one selected team. The
/// team gate is the registration counterpart of the fail-closed grant checks
/// in the proxy routes: a server whose grant is empty has nothing it may
/// read, so it is not registered at all. Pure so the gating is testable
/// without an app handle.
fn linear_read_server_account(account: &crate::connectors::ConnectorAccount) -> bool {
    account.provider == crate::connectors::ConnectorProvider::Linear
        && account.status == crate::connectors::ConnectorAccountStatus::Connected
        && !account.selected_teams.is_empty()
}

/// True when this account should back the `june_linear_actions` write server:
/// a read-eligible workspace that ALSO holds the `write` scope. A read-only
/// connect (the default bundle) must not register the write tools, or the
/// user would be asked to approve mutations Linear is guaranteed to reject.
/// They add write access through the settings "add access" flow.
fn linear_actions_server_account(account: &crate::connectors::ConnectorAccount) -> bool {
    linear_read_server_account(account)
        && account
            .scopes
            .iter()
            .any(|scope| scope == crate::connectors::scopes::LINEAR_WRITE)
}

/// True when this connected account should back the `june_github` read server:
/// a CONNECTED GitHub account. GitHub's repository boundary is enforced by the
/// App installation server-side (ADR-0036), so there is no selected-repository
/// gate here analogous to Linear's selected-team gate.
fn github_read_server_account(account: &crate::connectors::ConnectorAccount) -> bool {
    account.provider == crate::connectors::ConnectorProvider::Github
        && account.status == crate::connectors::ConnectorAccountStatus::Connected
}

/// True when this account should back the `june_github_actions` write server:
/// a connected GitHub account that ALSO holds the June-side `write` marker.
/// A read-only connect must not register the write tools (ADR-0036 §3).
fn github_actions_server_account(account: &crate::connectors::ConnectorAccount) -> bool {
    github_read_server_account(account)
        && account
            .scopes
            .iter()
            .any(|scope| scope == crate::connectors::scopes::GITHUB_WRITE)
}

/// Writes the connector MCP scripts and returns their configs. Google servers
/// require a connected account; Linear read tools additionally require selected
/// teams and Linear actions require write scope; Notion servers require a
/// connected hosted MCP account. Returns `None` when no provider passes its
/// registration gates.
/// v1 registers a single account context per provider; each proxy call
/// carries that account as `account_id`.
async fn sync_june_connector_mcps(
    app: &AppHandle,
    hermes_command: &str,
) -> Result<Option<ConnectorMcpConfigs>, AppError> {
    // Listing reads the non-secret DB index only (no keychain prompt). v1 uses
    // the first CONNECTED account per provider for the base servers;
    // multi-account is a documented follow-up. The provider filter matters:
    // the Gmail/Calendar servers must never bind to a Linear workspace (whose
    // email may even be empty), and `june_linear` binds to the workspace ID,
    // never an email. A `reconnect_required` account is skipped so a stale
    // first account does not hand a base server a dead identity while a
    // healthy account exists. The Linear resolution additionally requires a
    // non-empty selected-team set ([`linear_read_server_account`]): with no
    // grant there is nothing the server may read, so it does not exist.
    let accounts = match crate::connectors::list_runtime_accounts(app).await {
        Ok(accounts) => accounts,
        Err(error) => {
            // A DB read failure must not wedge the whole bridge start; skip the
            // connector servers and log a code only.
            tracing::warn!(error_code = %error.code, "connector account listing failed; skipping connector MCP registration");
            Vec::new()
        }
    };
    let account_email = accounts
        .iter()
        .find(|account| {
            account.provider == crate::connectors::ConnectorProvider::Google
                && account.status == crate::connectors::ConnectorAccountStatus::Connected
        })
        .map(|account| account.email.clone());
    let linear_workspace_id = accounts
        .iter()
        .find(|account| linear_read_server_account(account))
        .map(|account| account.account_id.clone());
    // The write server has a stricter gate than the read server: it also
    // requires the `write` scope, so a read-only connect never offers write
    // tools that would fail upstream.
    let linear_actions_workspace_id = accounts
        .iter()
        .find(|account| linear_actions_server_account(account))
        .map(|account| account.account_id.clone());
    // GitHub: keyed by the numeric user id (account_id). A connected account
    // always gets the read server; the write server also requires the
    // June-side `write` marker (ADR-0036 §3).
    let github_account_id = accounts
        .iter()
        .find(|account| github_read_server_account(account))
        .map(|account| account.account_id.clone());
    let github_actions_account_id = accounts
        .iter()
        .find(|account| github_actions_server_account(account))
        .map(|account| account.account_id.clone());

    // Earned-autonomy grants: one auto MCP server per row. Re-queried on every
    // spawn (and every connectors_apply_runtime restart), so new/removed grants
    // land in the rendered config.
    let grants = match crate::commands::repositories(app).await {
        Ok(repos) => repos.list_connector_grants().await.unwrap_or_default(),
        Err(error) => {
            tracing::warn!(error_code = %error.code, "connector grants query failed; skipping auto servers");
            Vec::new()
        }
    };

    let notion_connected = match crate::connectors::notion::status(app).await {
        Ok(status) => status.connected,
        Err(error) => {
            tracing::warn!(error_code = %error.code, "Notion connector status unavailable; skipping Notion MCP registration");
            false
        }
    };

    // Nothing to register: no connected account and no usable grant.
    if account_email.is_none()
        && linear_workspace_id.is_none()
        && github_account_id.is_none()
        && !notion_connected
        && grants
            .iter()
            .all(|grant| grant.account_id.trim().is_empty())
    {
        return Ok(None);
    }

    let data_dir = crate::app_paths::app_data_dir(app)
        .map_err(|error| AppError::new("june_connector_mcp_failed", error.to_string()))?;
    let mcp_dir = data_dir.join(JUNE_CONTEXT_MCP_DIR_NAME);
    fs::create_dir_all(&mcp_dir)
        .map_err(|error| AppError::new("june_connector_mcp_failed", error.to_string()))?;
    let command = hermes_python_command(hermes_command);

    // Write all six scripts up front: the base servers and every auto server
    // (which reuses the provider action script) point at these paths.
    let write_script = |script_name: &str, script: &str| -> Result<PathBuf, AppError> {
        let script_path = mcp_dir.join(script_name);
        fs::write(&script_path, script)
            .map_err(|error| AppError::new("june_connector_mcp_failed", error.to_string()))?;
        Ok(script_path)
    };
    let gmail_read_path = write_script(JUNE_GMAIL_MCP_SCRIPT_NAME, JUNE_GMAIL_MCP_SCRIPT)?;
    let gmail_actions_path = write_script(
        JUNE_GMAIL_ACTIONS_MCP_SCRIPT_NAME,
        JUNE_GMAIL_ACTIONS_MCP_SCRIPT,
    )?;
    let gcal_read_path = write_script(JUNE_GCAL_MCP_SCRIPT_NAME, JUNE_GCAL_MCP_SCRIPT)?;
    let gcal_actions_path = write_script(
        JUNE_GCAL_ACTIONS_MCP_SCRIPT_NAME,
        JUNE_GCAL_ACTIONS_MCP_SCRIPT,
    )?;
    let linear_read_path = write_script(JUNE_LINEAR_MCP_SCRIPT_NAME, JUNE_LINEAR_MCP_SCRIPT)?;
    let linear_actions_path = write_script(
        JUNE_LINEAR_ACTIONS_MCP_SCRIPT_NAME,
        JUNE_LINEAR_ACTIONS_MCP_SCRIPT,
    )?;
    let github_read_path = write_script(JUNE_GITHUB_MCP_SCRIPT_NAME, JUNE_GITHUB_MCP_SCRIPT)?;
    let github_actions_path = write_script(
        JUNE_GITHUB_ACTIONS_MCP_SCRIPT_NAME,
        JUNE_GITHUB_ACTIONS_MCP_SCRIPT,
    )?;
    let notion_path = write_script(JUNE_NOTION_MCP_SCRIPT_NAME, JUNE_NOTION_MCP_SCRIPT)?;
    let notion_actions_path = write_script(
        JUNE_NOTION_ACTIONS_MCP_SCRIPT_NAME,
        JUNE_NOTION_ACTIONS_MCP_SCRIPT,
    )?;

    let notion_config = notion_connected.then(|| JuneConnectorMcpConfig {
        command: command.clone(),
        script_path: notion_path.clone(),
        account_email: crate::connectors::notion::notion_account_email().to_string(),
    });
    let notion_actions_config = notion_connected.then(|| JuneConnectorMcpConfig {
        command: command.clone(),
        script_path: notion_actions_path.clone(),
        account_email: crate::connectors::notion::notion_account_email().to_string(),
    });

    let connector_config = |script_path: &PathBuf, account_id: &str| JuneConnectorMcpConfig {
        command: command.clone(),
        script_path: script_path.clone(),
        account_email: account_id.to_string(),
    };
    let base = if account_email.is_some()
        || linear_workspace_id.is_some()
        || github_account_id.is_some()
    {
        Some(ConnectorBaseMcpConfigs {
            gmail: account_email
                .as_deref()
                .map(|email| connector_config(&gmail_read_path, email)),
            gmail_actions: account_email
                .as_deref()
                .map(|email| connector_config(&gmail_actions_path, email)),
            gcal: account_email
                .as_deref()
                .map(|email| connector_config(&gcal_read_path, email)),
            gcal_actions: account_email
                .as_deref()
                .map(|email| connector_config(&gcal_actions_path, email)),
            linear: linear_workspace_id
                .as_deref()
                .map(|workspace_id| connector_config(&linear_read_path, workspace_id)),
            // Stricter gate than the read server: the write scope is also
            // required, so a read-only workspace never offers write tools.
            linear_actions: linear_actions_workspace_id
                .as_deref()
                .map(|workspace_id| connector_config(&linear_actions_path, workspace_id)),
            // GitHub read server: any connected account (ADR-0036).
            // The account id is the numeric GitHub user id (stringified).
            github: github_account_id
                .as_deref()
                .map(|account_id| connector_config(&github_read_path, account_id)),
            // Stricter gate: also requires the June-side `write` marker so
            // a read-only connect never exposes write tools that would be
            // refused by the proxy anyway (defence in depth).
            github_actions: github_actions_account_id
                .as_deref()
                .map(|account_id| connector_config(&github_actions_path, account_id)),
        })
    } else {
        None
    };

    let autos = grants
        .into_iter()
        // A grant with no account cannot resolve a token, so it can never run.
        .filter(|grant| !grant.account_id.trim().is_empty())
        .filter_map(|grant| {
            let script_path = match grant.provider.as_str() {
                "gmail" => gmail_actions_path.clone(),
                "gcal" => gcal_actions_path.clone(),
                _ => return None,
            };
            Some(ConnectorAutoMcpConfig {
                server_name: grant.server_name,
                command: command.clone(),
                script_path,
                account_email: grant.account_id,
                grant_token: grant.token,
                tools: grant.tools,
            })
        })
        .collect();

    Ok(Some(ConnectorMcpConfigs {
        base,
        notion: notion_config,
        notion_actions: notion_actions_config,
        autos,
    }))
}

fn remove_legacy_image_source_secret(hermes_home: &Path) -> Result<(), AppError> {
    let path = hermes_home.join(LEGACY_IMAGE_SOURCE_SECRET_FILE);
    match fs::remove_file(&path) {
        Ok(()) => Ok(()),
        Err(error) if error.kind() == io::ErrorKind::NotFound => Ok(()),
        Err(error) => Err(AppError::new(
            "june_image_mcp_failed",
            format!("failed to remove legacy image edit-source secret: {error}"),
        )),
    }
}

fn hermes_python_command(hermes_command: &str) -> String {
    let command_path = Path::new(hermes_command);
    if let Some(parent) = command_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
    {
        let candidates = if cfg!(target_os = "windows") {
            ["python.exe", "python"]
        } else {
            ["python3", "python"]
        };
        for candidate in candidates {
            let path = parent.join(candidate);
            if path.exists() {
                return path.to_string_lossy().into_owned();
            }
        }
    }
    default_python_command().to_string()
}

fn default_python_command() -> &'static str {
    if cfg!(target_os = "windows") {
        "python"
    } else {
        "python3"
    }
}

#[allow(clippy::too_many_arguments)]
fn sync_hermes_config(
    app: &AppHandle,
    hermes_home: &std::path::Path,
    provider_proxy_port: u16,
    provider_proxy_token: &str,
    memory_proxy_token: &str,
    recorder_proxy_token: &str,
    routine_browser_proxy_token: &str,
    connector_proxy_token: &str,
    computer_use_proxy_token: &str,
    obsidian_proxy_token: &str,
    supports_vision: bool,
    june_context_mcp: &JuneContextMcpConfig,
    june_web_mcp: &JuneWebMcpConfig,
    june_obsidian_mcp: &JuneObsidianMcpConfig,
    june_image_mcp: &JuneImageMcpConfig,
    june_video_mcp: Option<&JuneVideoMcpConfig>,
    june_recorder_mcp: &JuneRecorderMcpConfig,
    june_browser_mcp: &JuneBrowserMcpConfig,
    june_computer_use_mcp: &JuneComputerUseMcpConfig,
    june_connector_mcp: Option<&ConnectorMcpConfigs>,
) -> Result<(), AppError> {
    sync_hermes_config_with_external_dirs(
        hermes_home,
        provider_proxy_port,
        provider_proxy_token,
        memory_proxy_token,
        recorder_proxy_token,
        routine_browser_proxy_token,
        connector_proxy_token,
        computer_use_proxy_token,
        obsidian_proxy_token,
        supports_vision,
        june_context_mcp,
        june_web_mcp,
        june_obsidian_mcp,
        june_image_mcp,
        june_video_mcp,
        june_recorder_mcp,
        june_browser_mcp,
        june_computer_use_mcp,
        june_connector_mcp,
        &builtin_external_skill_dirs(app),
    )
}

#[allow(clippy::too_many_arguments)]
fn sync_hermes_config_with_external_dirs(
    hermes_home: &std::path::Path,
    provider_proxy_port: u16,
    provider_proxy_token: &str,
    memory_proxy_token: &str,
    recorder_proxy_token: &str,
    routine_browser_proxy_token: &str,
    connector_proxy_token: &str,
    computer_use_proxy_token: &str,
    obsidian_proxy_token: &str,
    supports_vision: bool,
    june_context_mcp: &JuneContextMcpConfig,
    june_web_mcp: &JuneWebMcpConfig,
    june_obsidian_mcp: &JuneObsidianMcpConfig,
    june_image_mcp: &JuneImageMcpConfig,
    june_video_mcp: Option<&JuneVideoMcpConfig>,
    june_recorder_mcp: &JuneRecorderMcpConfig,
    june_browser_mcp: &JuneBrowserMcpConfig,
    june_computer_use_mcp: &JuneComputerUseMcpConfig,
    june_connector_mcp: Option<&ConnectorMcpConfigs>,
    default_external_skill_dirs: &[PathBuf],
) -> Result<(), AppError> {
    let model = crate::providers::generation_model();
    let base_url = format!("http://127.0.0.1:{provider_proxy_port}/v1");
    let config_path = hermes_home.join("config.yaml");
    let _config_lock = HermesConfigWriterLock::acquire(&config_path)?;
    let external_skill_dirs =
        effective_external_skill_dirs_from_config(&config_path, default_external_skill_dirs);
    let connector_base = june_connector_mcp.and_then(|configs| configs.base.as_ref());
    let mcp_configs = BuiltinMcpConfigs {
        context: Some(june_context_mcp),
        web: Some(june_web_mcp),
        obsidian: Some(june_obsidian_mcp),
        image: Some(june_image_mcp),
        video: june_video_mcp,
        recorder: Some(june_recorder_mcp),
        browser: Some(june_browser_mcp),
        computer_use: Some(june_computer_use_mcp),
        gmail: connector_base.and_then(|base| base.gmail.as_ref()),
        gmail_actions: connector_base.and_then(|base| base.gmail_actions.as_ref()),
        gcal: connector_base.and_then(|base| base.gcal.as_ref()),
        gcal_actions: connector_base.and_then(|base| base.gcal_actions.as_ref()),
        linear: connector_base.and_then(|base| base.linear.as_ref()),
        linear_actions: connector_base.and_then(|base| base.linear_actions.as_ref()),
        notion: june_connector_mcp.and_then(|configs| configs.notion.as_ref()),
        notion_actions: june_connector_mcp.and_then(|configs| configs.notion_actions.as_ref()),
        github: connector_base.and_then(|base| base.github.as_ref()),
        github_actions: connector_base.and_then(|base| base.github_actions.as_ref()),
        connector_autos: june_connector_mcp
            .map(|configs| configs.autos.as_slice())
            .unwrap_or(&[]),
    };
    let memory_enabled = mcp_configs.context.map_or(true, |context| {
        june_memory_enabled(&context.memory_settings_path)
    });
    let cron_toolsets = cron_platform_toolsets(&mcp_configs);
    let config = render_hermes_config(
        &model,
        supports_vision,
        &base_url,
        provider_proxy_token,
        memory_proxy_token,
        recorder_proxy_token,
        routine_browser_proxy_token,
        connector_proxy_token,
        computer_use_proxy_token,
        obsidian_proxy_token,
        &cron_toolsets,
        &external_skill_dirs,
        mcp_configs,
    );
    // MERGE over the existing config, never replace it: the jailed dashboard
    // persists admin changes (user-added MCP servers, tool filters, OAuth
    // client names, skill config) into this same file, and a plain overwrite
    // wiped them on every June spawn. June's rendered keys still win — the
    // provider proxy port/token legitimately change per spawn — but every key
    // June does not render survives.
    let source_backup_created =
        preserve_replaced_hermes_config_if_needed(&config_path, memory_enabled)?;
    let mut merged =
        serde_yaml::from_str::<serde_yaml::Value>(&merge_hermes_config(&config_path, &config))
            .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    let repaired_memory_shape = apply_memory_toolset_policy(&mut merged, memory_enabled);
    let repaired_obsidian_shape = apply_obsidian_skill_policy(&mut merged);
    let repaired_invalid_shape = repaired_memory_shape || repaired_obsidian_shape;
    if repaired_invalid_shape && !source_backup_created {
        match fs::read(&config_path) {
            Ok(existing) => {
                backup_corrupt_hermes_config(&config_path, &existing)?;
            }
            Err(error) if error.kind() == io::ErrorKind::NotFound => {}
            Err(error) => {
                return Err(AppError::new(
                    "hermes_bridge_config_failed",
                    error.to_string(),
                ))
            }
        }
    }
    let merged = serde_yaml::to_string(&merged)
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    write_hermes_config_atomic(&config_path, &merged)
}

/// Deep-merges June's freshly rendered config over the existing `config.yaml`,
/// returning the YAML to write. June's leaves win on conflict; mappings merge
/// recursively, so a user-added `mcp_servers.<name>` entry (and its `oauth` /
/// `tools` blocks, or `skills.config` values) survives while June's
/// `june_context` / `june_web` entries and the per-spawn model proxy settings
/// refresh. A missing or unparsable existing file falls back to the rendered
/// config alone, matching the previous overwrite behavior.
fn merge_hermes_config(existing_path: &std::path::Path, rendered: &str) -> String {
    let Ok(existing_text) = std::fs::read_to_string(existing_path) else {
        return rendered.to_string();
    };
    let Ok(mut existing) = serde_yaml::from_str::<serde_yaml::Value>(&existing_text) else {
        return rendered.to_string();
    };
    let Ok(overlay) = serde_yaml::from_str::<serde_yaml::Value>(rendered) else {
        return rendered.to_string();
    };
    // Drop June-owned ephemeral per-routine and connector MCP entries before
    // merging. The overlay re-adds them only while the connector is active, so
    // a disconnect (or a removed auto grant) renders none and the deep merge
    // must not preserve the old june_gmail*/june_gcal*/per-job auto-server keys
    // and keep exposing stale connector tools. User-added servers and June's
    // always-rendered entries (june_context, june_web, ...) are untouched.
    prune_connector_mcp_servers(&mut existing);
    prune_routine_browser_mcp_servers(&mut existing);
    prune_legacy_browser_context_env(&mut existing);
    let merged = deep_merge_yaml(existing, overlay);
    serde_yaml::to_string(&merged).unwrap_or_else(|_| rendered.to_string())
}

/// Mutates only June's global native-memory policy. Every other agent setting,
/// user-added MCP server, skill setting, and unrelated disabled toolset stays
/// intact. `memory` is normalized to at most one entry while disabled and is
/// the only entry removed when memory is re-enabled.
fn apply_memory_toolset_policy(config: &mut serde_yaml::Value, memory_enabled: bool) -> bool {
    let serde_yaml::Value::Mapping(root) = config else {
        return false;
    };
    let agent_key = serde_yaml::Value::String("agent".to_string());
    let disabled_key = serde_yaml::Value::String("disabled_toolsets".to_string());

    if memory_enabled {
        let Some(agent) = root.get_mut(&agent_key) else {
            return false;
        };
        let Some(agent) = agent.as_mapping_mut() else {
            return false;
        };
        let Some(disabled) = agent.get_mut(&disabled_key) else {
            return false;
        };
        let Some(disabled) = disabled.as_sequence_mut() else {
            return false;
        };
        disabled.retain(|item| item.as_str() != Some("memory"));
        if disabled.is_empty() {
            agent.remove(&disabled_key);
        }
        return false;
    }

    let mut repaired_invalid_shape = false;
    let agent = root
        .entry(agent_key)
        .or_insert_with(|| serde_yaml::Value::Mapping(Default::default()));
    if !agent.is_mapping() {
        *agent = serde_yaml::Value::Mapping(Default::default());
        repaired_invalid_shape = true;
    }
    let agent = agent
        .as_mapping_mut()
        .expect("agent was normalized to a mapping");
    let disabled = agent.entry(disabled_key).or_insert_with(|| {
        serde_yaml::Value::Sequence(vec![serde_yaml::Value::String("memory".to_string())])
    });
    let Some(disabled) = disabled.as_sequence_mut() else {
        *disabled =
            serde_yaml::Value::Sequence(vec![serde_yaml::Value::String("memory".to_string())]);
        return true;
    };
    disabled.retain(|item| item.as_str() != Some("memory"));
    disabled.push(serde_yaml::Value::String("memory".to_string()));
    repaired_invalid_shape
}

/// The pinned upstream `obsidian` skill guesses an ambient vault path. June
/// owns the replacement under a distinct name, so disable only that upstream
/// identity while preserving every unrelated user skill preference.
fn apply_obsidian_skill_policy(config: &mut serde_yaml::Value) -> bool {
    let serde_yaml::Value::Mapping(root) = config else {
        return false;
    };
    let skills_key = serde_yaml::Value::String("skills".to_string());
    let disabled_key = serde_yaml::Value::String("disabled".to_string());
    let skills = root
        .entry(skills_key)
        .or_insert_with(|| serde_yaml::Value::Mapping(Default::default()));
    let mut repaired_invalid_shape = false;
    if !skills.is_mapping() {
        *skills = serde_yaml::Value::Mapping(Default::default());
        repaired_invalid_shape = true;
    }
    let skills = skills
        .as_mapping_mut()
        .expect("skills was normalized to a mapping");
    let disabled = skills
        .entry(disabled_key)
        .or_insert_with(|| serde_yaml::Value::Sequence(Vec::new()));
    if !disabled.is_sequence() {
        *disabled = serde_yaml::Value::Sequence(Vec::new());
        repaired_invalid_shape = true;
    }
    let disabled = disabled
        .as_sequence_mut()
        .expect("skills.disabled was normalized to a sequence");
    disabled.retain(|item| item.as_str() != Some("obsidian"));
    disabled.push(serde_yaml::Value::String("obsidian".to_string()));
    repaired_invalid_shape
}

fn hermes_config_has_invalid_root(config: &serde_yaml::Value) -> bool {
    !config.is_mapping()
}

fn memory_policy_has_invalid_shape(config: &serde_yaml::Value) -> bool {
    let Some(agent) = config.get("agent") else {
        return false;
    };
    let Some(agent) = agent.as_mapping() else {
        return true;
    };
    agent
        .get(serde_yaml::Value::String("disabled_toolsets".to_string()))
        .is_some_and(|disabled| !disabled.is_sequence())
}

fn obsidian_skill_policy_has_invalid_shape(config: &serde_yaml::Value) -> bool {
    let Some(skills) = config.get("skills") else {
        return false;
    };
    let Some(skills) = skills.as_mapping() else {
        return true;
    };
    skills
        .get(serde_yaml::Value::String("disabled".to_string()))
        .is_some_and(|disabled| !disabled.is_sequence())
}

/// Preserve config text before a normal spawn replaces YAML that cannot be
/// safely merged or must repair a malformed disabled-toolset shape. This is
/// especially important while Memory is off: fail closed with a valid global
/// denylist, but retain the original bytes beside config.yaml for diagnosis.
fn preserve_replaced_hermes_config_if_needed(
    config_path: &Path,
    memory_enabled: bool,
) -> Result<bool, AppError> {
    let existing = match fs::read_to_string(config_path) {
        Ok(existing) => existing,
        Err(error) if error.kind() == io::ErrorKind::NotFound => return Ok(false),
        Err(error) => {
            return Err(AppError::new(
                "hermes_bridge_config_failed",
                error.to_string(),
            ))
        }
    };
    let parsed = serde_yaml::from_str::<serde_yaml::Value>(&existing);
    let needs_backup = match parsed {
        Ok(ref config) => {
            hermes_config_has_invalid_root(config)
                || (!memory_enabled && memory_policy_has_invalid_shape(config))
                || obsidian_skill_policy_has_invalid_shape(config)
        }
        Err(_) => true,
    };
    if needs_backup {
        backup_corrupt_hermes_config(config_path, existing.as_bytes())?;
    }
    Ok(needs_backup)
}

/// Narrow, connection-independent config mutation used by the Memory toggle.
/// Missing and corrupt files fail closed while disabling: June writes a valid
/// minimal policy, preserving corrupt bytes first. Enabling against corrupt
/// YAML leaves it untouched; no deny can be safely identified or removed, and
/// the setting permits memory in that state anyway.
fn update_hermes_memory_policy_file(
    config_path: &Path,
    memory_enabled: bool,
) -> Result<(), AppError> {
    let _config_lock = HermesConfigWriterLock::acquire(config_path)?;
    let existing = match fs::read_to_string(config_path) {
        Ok(existing) => Some(existing),
        Err(error) if error.kind() == io::ErrorKind::NotFound => None,
        Err(error) => {
            return Err(AppError::new(
                "hermes_bridge_config_failed",
                error.to_string(),
            ))
        }
    };
    if memory_enabled && existing.is_none() {
        return Ok(());
    }

    let mut config = match existing.as_deref() {
        Some(raw) => match serde_yaml::from_str::<serde_yaml::Value>(raw) {
            Ok(config) if config.is_mapping() => config,
            Ok(_) | Err(_) if memory_enabled => return Ok(()),
            Ok(_) | Err(_) => {
                backup_corrupt_hermes_config(config_path, raw.as_bytes())?;
                serde_yaml::Value::Mapping(Default::default())
            }
        },
        None => serde_yaml::Value::Mapping(Default::default()),
    };
    let repaired_invalid_shape = apply_memory_toolset_policy(&mut config, memory_enabled);
    if repaired_invalid_shape {
        if let Some(raw) = existing.as_deref() {
            backup_corrupt_hermes_config(config_path, raw.as_bytes())?;
        }
    }
    let serialized = serde_yaml::to_string(&config)
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    write_hermes_config_atomic(config_path, &serialized)
}

/// Re-read the fail-closed authoritative setting at the point of mutation.
/// Keeping the setting out of the caller's arguments prevents an older toggle
/// from overwriting a newer one after waiting for the shared config writer lock.
fn apply_persisted_memory_policy_file(
    config_path: &Path,
    settings_path: &Path,
) -> Result<(), AppError> {
    update_hermes_memory_policy_file(config_path, june_memory_enabled(settings_path))
}

fn backup_corrupt_hermes_config(config_path: &Path, contents: &[u8]) -> Result<PathBuf, AppError> {
    let parent = config_path.parent().ok_or_else(|| {
        AppError::new(
            "hermes_bridge_config_failed",
            "Hermes config path has no parent directory.",
        )
    })?;
    fs::create_dir_all(parent)
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    let backup_path = parent.join(format!(
        "{HERMES_CONFIG_CORRUPT_BACKUP_PREFIX}{}.bak",
        uuid::Uuid::new_v4()
    ));
    let mut options = OpenOptions::new();
    options.write(true).create_new(true);
    #[cfg(unix)]
    {
        use std::os::unix::fs::OpenOptionsExt;
        options.mode(0o600);
    }
    let mut backup = options
        .open(&backup_path)
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    backup
        .write_all(contents)
        .and_then(|_| backup.sync_all())
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    Ok(backup_path)
}

fn write_hermes_config_atomic(config_path: &Path, contents: &str) -> Result<(), AppError> {
    let target_path = hermes_config_replacement_target(config_path)
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    let parent = target_path.parent().ok_or_else(|| {
        AppError::new(
            "hermes_bridge_config_failed",
            "Hermes config path has no parent directory.",
        )
    })?;
    fs::create_dir_all(parent)
        .map_err(|error| AppError::new("hermes_bridge_config_failed", error.to_string()))?;
    let temporary_path = parent.join(format!(
        "{HERMES_CONFIG_ATOMIC_TEMP_PREFIX}{}.tmp",
        uuid::Uuid::new_v4()
    ));
    let write_result = (|| -> io::Result<()> {
        let mut options = OpenOptions::new();
        options.write(true).create_new(true);
        #[cfg(unix)]
        {
            use std::os::unix::fs::OpenOptionsExt;
            // config.yaml contains on-device provider proxy and connector
            // credentials. Match Hermes' mkstemp writer so a new file is never
            // briefly broader than owner-only before final metadata is applied.
            options.mode(0o600);
        }
        let mut temporary = options.open(&temporary_path)?;
        preserve_hermes_config_metadata(&target_path, &temporary)?;
        temporary.write_all(contents.as_bytes())?;
        temporary.sync_all()?;
        drop(temporary);
        replace_file(&temporary_path, &target_path)
    })();
    if let Err(error) = write_result {
        let _ = fs::remove_file(&temporary_path);
        return Err(AppError::new(
            "hermes_bridge_config_failed",
            error.to_string(),
        ));
    }
    Ok(())
}

/// Resolve an existing symlink before replacing config.yaml. Replacing the link
/// itself would detach managed/dotfile-backed Hermes homes and leave the real
/// config unchanged. A dangling link fails closed instead of being destroyed.
fn hermes_config_replacement_target(config_path: &Path) -> io::Result<PathBuf> {
    match fs::symlink_metadata(config_path) {
        Ok(metadata) if metadata.file_type().is_symlink() => fs::canonicalize(config_path),
        Ok(_) => Ok(config_path.to_path_buf()),
        Err(error) if error.kind() == io::ErrorKind::NotFound => Ok(config_path.to_path_buf()),
        Err(error) => Err(error),
    }
}

fn preserve_hermes_config_metadata(target_path: &Path, temporary: &fs::File) -> io::Result<()> {
    let metadata = match fs::metadata(target_path) {
        Ok(metadata) => metadata,
        Err(error) if error.kind() == io::ErrorKind::NotFound => return Ok(()),
        Err(error) => return Err(error),
    };
    temporary.set_permissions(metadata.permissions())?;

    #[cfg(target_os = "macos")]
    {
        use std::os::fd::AsRawFd;

        // Preserve the existing file's ACL in addition to its POSIX mode. The
        // content is deliberately excluded; only COPYFILE_SECURITY metadata is
        // copied onto the still-empty temporary file before secret bytes land.
        const COPYFILE_SECURITY: u32 = (1 << 0) | (1 << 1);
        extern "C" {
            fn fcopyfile(
                from: libc::c_int,
                to: libc::c_int,
                state: *mut libc::c_void,
                flags: u32,
            ) -> libc::c_int;
        }
        let source = fs::File::open(target_path)?;
        let result = unsafe {
            fcopyfile(
                source.as_raw_fd(),
                temporary.as_raw_fd(),
                std::ptr::null_mut(),
                COPYFILE_SECURITY,
            )
        };
        if result != 0 {
            return Err(io::Error::last_os_error());
        }
    }

    Ok(())
}

/// Removes June's connector MCP server entries (`june_gmail`, `june_gcal`,
/// `june_linear`, the `_actions` servers, and the per-job `june_gmail_auto_*`
/// / `june_gcal_auto_*` servers) from a parsed config so a fresh render alone
/// decides which, if any, still exist.
fn prune_connector_mcp_servers(config: &mut serde_yaml::Value) {
    let Some(mcp_servers) = config
        .get_mut("mcp_servers")
        .and_then(serde_yaml::Value::as_mapping_mut)
    else {
        return;
    };
    mcp_servers.retain(|key, _| {
        key.as_str()
            .map(|name| !is_june_connector_server_name(name))
            .unwrap_or(true)
    });
}

fn prune_routine_browser_mcp_servers(config: &mut serde_yaml::Value) {
    let Some(mcp_servers) = config
        .get_mut("mcp_servers")
        .and_then(serde_yaml::Value::as_mapping_mut)
    else {
        return;
    };
    mcp_servers.retain(|key, _| {
        key.as_str()
            .map(|name| !is_routine_browser_server_name(name))
            .unwrap_or(true)
    });
}

/// Removes the session-marker interpolation used before browser MCP entries
/// carried an explicit context. A recursive merge preserves omitted mapping
/// leaves, so this migration must delete the obsolete June-owned env keys.
fn prune_legacy_browser_context_env(config: &mut serde_yaml::Value) {
    let Some(env) = config
        .get_mut("mcp_servers")
        .and_then(|servers| servers.get_mut(JUNE_BROWSER_MCP_SERVER_NAME))
        .and_then(|browser| browser.get_mut("env"))
        .and_then(serde_yaml::Value::as_mapping_mut)
    else {
        return;
    };
    env.retain(|key, _| {
        !matches!(
            key.as_str(),
            Some(LEGACY_JUNE_BROWSER_MCP_CRON_CONTEXT_ENV)
                | Some(LEGACY_JUNE_BROWSER_MCP_GATEWAY_CONTEXT_ENV)
        )
    });
}

fn is_routine_browser_server_name(name: &str) -> bool {
    name.starts_with("june_browser_routine_")
}

/// True for every MCP server name June owns for connectors. The `_` prefixes
/// cover the `_actions` servers (including `june_linear_actions` and
/// `june_github_actions`) and the per-job `_auto_<jobid>` servers.
fn is_june_connector_server_name(name: &str) -> bool {
    name == JUNE_GMAIL_MCP_SERVER_NAME
        || name == JUNE_GCAL_MCP_SERVER_NAME
        || name == JUNE_LINEAR_MCP_SERVER_NAME
        || name == JUNE_NOTION_MCP_SERVER_NAME
        || name == JUNE_NOTION_ACTIONS_MCP_SERVER_NAME
        || name == JUNE_GITHUB_MCP_SERVER_NAME
        || name.starts_with("june_gmail_")
        || name.starts_with("june_gcal_")
        || name.starts_with("june_linear_")
        || name.starts_with("june_github_")
}

/// Resolve the dashboard/TUI toolset pin from the merged Hermes config while
/// excluding every per-routine connector autonomy server. This mirrors the
/// pinned runtime's CLI-platform behavior: an explicit MCP name is an
/// allowlist; otherwise all enabled MCP servers are included. User-added MCPs
/// and native toolset choices survive unchanged.
fn hermes_interactive_toolsets(config_path: &Path) -> Vec<String> {
    let config = std::fs::read_to_string(config_path)
        .ok()
        .and_then(|text| serde_yaml::from_str::<serde_yaml::Value>(&text).ok());
    let Some(config) = config else {
        // Fail closed for MCP access: a malformed config gets the native
        // interactive default but no globally registered MCP server.
        return JUNE_INTERACTIVE_NATIVE_TOOLSETS
            .iter()
            .map(|name| (*name).to_string())
            .collect();
    };

    let mut selected: Vec<String> = config
        .get("platform_toolsets")
        .and_then(|value| value.get("cli"))
        .and_then(serde_yaml::Value::as_sequence)
        .map(|items| {
            items
                .iter()
                .filter_map(|item| item.as_str().map(str::to_string))
                .filter(|name| !is_per_routine_mcp_server_name(name))
                .collect()
        })
        .unwrap_or_else(|| vec!["hermes-cli".to_string()]);

    // The upstream composite contains its direct browser and computer-use
    // implementations. Expand it before handing the list to the TUI gateway,
    // which accepts only an allowlist and does not apply agent.disabled_toolsets.
    // Direct selections are filtered too. This keeps the app-owned brokers as
    // the only way either capability can enter an interactive June session.
    let had_cli_composite = selected.iter().any(|name| {
        name == "hermes-cli"
            || name == "coding"
            || name == "hermes-acp"
            || name == "hermes-api-server"
            || name == "hermes-gateway"
    });
    selected.retain(|name| {
        !matches!(
            name.as_str(),
            "hermes-cli"
                | "coding"
                | "hermes-acp"
                | "hermes-api-server"
                | "hermes-gateway"
                | "browser"
                | "browser_tools"
                | "computer_use"
        )
    });
    if had_cli_composite {
        selected.extend(
            JUNE_INTERACTIVE_NATIVE_TOOLSETS
                .iter()
                .map(|name| (*name).to_string()),
        );
    }

    let enabled_mcp: Vec<String> = config
        .get("mcp_servers")
        .and_then(serde_yaml::Value::as_mapping)
        .into_iter()
        .flat_map(|servers| servers.iter())
        .filter_map(|(name, settings)| {
            let name = name.as_str()?;
            let enabled = settings
                .get("enabled")
                .and_then(serde_yaml::Value::as_bool)
                .unwrap_or(true);
            (enabled && !is_per_routine_mcp_server_name(name)).then(|| name.to_string())
        })
        .collect();
    let has_explicit_mcp = selected.iter().any(|name| enabled_mcp.contains(name));
    let disables_mcp = selected.iter().any(|name| name == "no_mcp");
    if !has_explicit_mcp && !disables_mcp {
        selected.extend(enabled_mcp);
    }
    selected.dedup();
    selected
}

fn is_june_connector_auto_server_name(name: &str) -> bool {
    name.starts_with("june_gmail_auto_") || name.starts_with("june_gcal_auto_")
}

fn is_per_routine_mcp_server_name(name: &str) -> bool {
    is_june_connector_auto_server_name(name) || is_routine_browser_server_name(name)
}

/// Recursive overlay merge: mappings merge key by key (overlay wins on leaf
/// conflicts); any non-mapping overlay value replaces the base outright.
fn deep_merge_yaml(base: serde_yaml::Value, overlay: serde_yaml::Value) -> serde_yaml::Value {
    match (base, overlay) {
        (serde_yaml::Value::Mapping(mut base_map), serde_yaml::Value::Mapping(overlay_map)) => {
            for (key, overlay_value) in overlay_map {
                let merged = match base_map.remove(&key) {
                    Some(base_value) => deep_merge_yaml(base_value, overlay_value),
                    None => overlay_value,
                };
                base_map.insert(key, merged);
            }
            serde_yaml::Value::Mapping(base_map)
        }
        (_, overlay) => overlay,
    }
}

struct BuiltinMcpConfigs<'a> {
    context: Option<&'a JuneContextMcpConfig>,
    web: Option<&'a JuneWebMcpConfig>,
    obsidian: Option<&'a JuneObsidianMcpConfig>,
    image: Option<&'a JuneImageMcpConfig>,
    video: Option<&'a JuneVideoMcpConfig>,
    recorder: Option<&'a JuneRecorderMcpConfig>,
    browser: Option<&'a JuneBrowserMcpConfig>,
    /// Always rendered so a revoked or not-yet-ready grant overwrites any
    /// stale enabled value left in the merged Hermes config.
    computer_use: Option<&'a JuneComputerUseMcpConfig>,
    gmail: Option<&'a JuneConnectorMcpConfig>,
    gmail_actions: Option<&'a JuneConnectorMcpConfig>,
    gcal: Option<&'a JuneConnectorMcpConfig>,
    gcal_actions: Option<&'a JuneConnectorMcpConfig>,
    /// The read-only Linear server.
    linear: Option<&'a JuneConnectorMcpConfig>,
    /// The Linear write server. Like the other action servers it never
    /// enters the cron allowlist; unlike them it has no earned-autonomy
    /// variant, so every call parks for approval.
    linear_actions: Option<&'a JuneConnectorMcpConfig>,
    notion: Option<&'a JuneConnectorMcpConfig>,
    notion_actions: Option<&'a JuneConnectorMcpConfig>,
    /// The read-only GitHub server (ADR-0036).
    github: Option<&'a JuneConnectorMcpConfig>,
    /// The GitHub write server. No earned-autonomy variant: every write
    /// parks for approval.
    github_actions: Option<&'a JuneConnectorMcpConfig>,
    /// Per-job earned-autonomy servers (0..N). Never in the cron allowlist;
    /// reached only via a routine's explicit per-job `enabled_toolsets`.
    connector_autos: &'a [ConnectorAutoMcpConfig],
}

/// The `platform_toolsets.cron` allowlist a routine runs with when it has no
/// per-job override. It is the sandboxed toolset list PLUS the read-only
/// built-in MCP servers that are registered. Naming any MCP server here flips
/// cron's auto-include off (Hermes tools_config semantics), so every read
/// server that should stay available to routines MUST be listed. The connector
/// ACTION servers are deliberately excluded: they are added per job only when
/// the user picks approval or autonomous trust for that routine.
fn cron_platform_toolsets(configs: &BuiltinMcpConfigs<'_>) -> String {
    // When the user turns Memory off, the native Hermes `memory` toolset must
    // go too — not just June's SOUL guidance and the june_context memory
    // tools. Otherwise a routine could still read/write Hermes' unscoped,
    // uninspectable memory store, contradicting the global off switch.
    let memory_enabled = configs.context.map_or(true, |context| {
        june_memory_enabled(&context.memory_settings_path)
    });
    let mut items: Vec<String> = CRON_SANDBOXED_TOOLSETS
        .iter()
        .filter(|toolset| memory_enabled || **toolset != "memory")
        .map(|toolset| toolset.to_string())
        .collect();
    if configs.context.is_some() {
        items.push(JUNE_CONTEXT_MCP_SERVER_NAME.to_string());
    }
    if configs.web.is_some() {
        items.push(JUNE_WEB_MCP_SERVER_NAME.to_string());
    }
    // Vault paths are intentional interactive discovery only. Routines do not
    // receive this server through their ambient cron allowlist.
    if configs.image.is_some() {
        items.push(JUNE_IMAGE_MCP_SERVER_NAME.to_string());
    }
    if configs.recorder.is_some() {
        items.push(JUNE_RECORDER_MCP_SERVER_NAME.to_string());
    }
    if configs.video.is_some() {
        items.push(JUNE_VIDEO_MCP_SERVER_NAME.to_string());
    }
    if configs.gmail.is_some() {
        items.push(JUNE_GMAIL_MCP_SERVER_NAME.to_string());
    }
    if configs.gcal.is_some() {
        items.push(JUNE_GCAL_MCP_SERVER_NAME.to_string());
    }
    // june_linear joins the ambient read toolsets exactly like the gmail/gcal
    // read servers: reads cannot mutate, and the selected-team enforcement in
    // the proxy routes applies identically in every context.
    if configs.linear.is_some() {
        items.push(JUNE_LINEAR_MCP_SERVER_NAME.to_string());
    }
    if configs.notion.is_some() {
        items.push(JUNE_NOTION_MCP_SERVER_NAME.to_string());
    }
    // june_github joins the ambient read toolsets. Repository access is
    // enforced by GitHub's App installation server-side; the read routes
    // carry no June-side team-grant check (ADR-0036).
    if configs.github.is_some() {
        items.push(JUNE_GITHUB_MCP_SERVER_NAME.to_string());
    }
    items.join(", ")
}

fn effective_external_skill_dirs(hermes_home: &Path, default_dirs: &[PathBuf]) -> Vec<PathBuf> {
    effective_external_skill_dirs_from_config(&hermes_home.join("config.yaml"), default_dirs)
}

fn effective_external_skill_dirs_from_config(
    config_path: &Path,
    default_dirs: &[PathBuf],
) -> Vec<PathBuf> {
    let mut dirs = Vec::new();
    let config_dir = config_path.parent();
    for dir in default_dirs {
        push_external_skill_dir(&mut dirs, dir.clone(), config_dir);
    }
    for dir in existing_external_skill_dirs(config_path) {
        let dir = external_skill_dir_from_config_path(config_path, dir);
        push_external_skill_dir(&mut dirs, dir, config_dir);
    }
    dirs
}

fn existing_external_skill_dirs(config_path: &Path) -> Vec<PathBuf> {
    let Ok(existing_text) = fs::read_to_string(config_path) else {
        return Vec::new();
    };
    let Ok(existing) = serde_yaml::from_str::<serde_yaml::Value>(&existing_text) else {
        return Vec::new();
    };
    external_skill_dirs_from_config_value(&existing)
}

fn external_skill_dirs_from_config_value(config: &serde_yaml::Value) -> Vec<PathBuf> {
    let Some(external_dirs) = yaml_mapping_get(config, "skills")
        .and_then(|skills| yaml_mapping_get(skills, "external_dirs"))
    else {
        return Vec::new();
    };
    match external_dirs {
        serde_yaml::Value::String(raw) => external_skill_dir_from_config_entry(raw)
            .into_iter()
            .collect(),
        serde_yaml::Value::Sequence(entries) => entries
            .iter()
            .filter_map(|entry| match entry {
                serde_yaml::Value::String(raw) => external_skill_dir_from_config_entry(raw),
                _ => None,
            })
            .collect(),
        _ => Vec::new(),
    }
}

fn yaml_mapping_get<'a>(value: &'a serde_yaml::Value, key: &str) -> Option<&'a serde_yaml::Value> {
    let serde_yaml::Value::Mapping(mapping) = value else {
        return None;
    };
    let lookup = serde_yaml::Value::String(key.to_string());
    mapping.get(&lookup)
}

fn external_skill_dir_from_config_entry(raw: &str) -> Option<PathBuf> {
    let trimmed = raw.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(PathBuf::from(trimmed))
    }
}

fn external_skill_dir_from_config_path(config_path: &Path, dir: PathBuf) -> PathBuf {
    let Some(config_dir) = config_path.parent() else {
        return dir;
    };
    if should_anchor_external_config_dir(&dir) {
        normalize_path_lexically(config_dir.join(dir))
    } else {
        dir
    }
}

fn should_anchor_external_config_dir(dir: &Path) -> bool {
    if dir.is_absolute() {
        return false;
    }
    let raw = dir.to_string_lossy();
    !(raw == "~" || raw.starts_with("~/") || raw.contains('$'))
}

fn push_external_skill_dir(dirs: &mut Vec<PathBuf>, dir: PathBuf, relative_base: Option<&Path>) {
    if dir.as_os_str().is_empty() {
        return;
    }
    // Strip the Windows verbatim path prefix (`\\?\`) so it never leaks into
    // config.yaml or the UI. `canonicalize()` (and some Tauri path resolvers)
    // add this prefix on Windows; `dunce::simplified` removes it when it is
    // safe to do so (a no-op on non-Windows).
    let dir = dunce::simplified(&dir).to_path_buf();
    let identity = external_skill_dir_identity(&dir, relative_base);
    if dirs
        .iter()
        .any(|existing| external_skill_dir_identity(existing, relative_base) == identity)
    {
        return;
    }
    dirs.push(dir);
}

fn external_skill_dir_identity(dir: &Path, relative_base: Option<&Path>) -> PathBuf {
    let path = external_skill_dir_scan_path_from_base(dir, relative_base)
        .unwrap_or_else(|| dir.to_path_buf());
    path.canonicalize()
        .unwrap_or_else(|_| normalize_path_lexically(path))
}

/// Renders the `config.yaml` June owns for every Hermes spawn. Pure so the
/// rendered YAML (including the `skills.external_dirs` block) can be asserted in
/// tests. Hermes deep-merges these keys over its own defaults, so June only
/// writes the values it controls.
#[allow(clippy::too_many_arguments)]
fn render_hermes_config(
    model: &str,
    supports_vision: bool,
    base_url: &str,
    provider_proxy_token: &str,
    memory_proxy_token: &str,
    recorder_proxy_token: &str,
    routine_browser_proxy_token: &str,
    connector_proxy_token: &str,
    computer_use_proxy_token: &str,
    obsidian_proxy_token: &str,
    cron_toolsets: &str,
    external_skill_dirs: &[PathBuf],
    mcp_configs: BuiltinMcpConfigs<'_>,
) -> String {
    let skills_block = if external_skill_dirs.is_empty() {
        "  external_dirs: []\n".to_string()
    } else {
        let mut block = String::from("  external_dirs:\n");
        for dir in external_skill_dirs {
            block.push_str(&format!("    - {}\n", yaml_string(&dir.to_string_lossy())));
        }
        block
    };
    let mcp_servers_block = render_mcp_servers_config(
        mcp_configs,
        base_url,
        provider_proxy_token,
        memory_proxy_token,
        recorder_proxy_token,
        routine_browser_proxy_token,
        connector_proxy_token,
        computer_use_proxy_token,
        obsidian_proxy_token,
    );
    format!(
        r#"model:
  default: {model}
  provider: custom
  base_url: {base_url}
  api_key: {provider_proxy_token}
  api_mode: chat_completions
  supports_vision: {supports_vision}
agent:
  max_turns: 90
  api_max_retries: 3
  disabled_toolsets: [{upstream_disabled_toolsets}]
approvals:
  mode: manual
  cron_mode: deny
display:
  skin: mono
platform_toolsets:
  cron: [{cron_toolsets}]
skills:
{skills_block}{mcp_servers_block}"#,
        model = yaml_string(model),
        base_url = yaml_string(base_url),
        provider_proxy_token = yaml_string(provider_proxy_token),
        upstream_disabled_toolsets = UPSTREAM_DISABLED_TOOLSETS.join(", "),
    )
}

/// registers. Built-in entries live under one key so Hermes deep-merges a
/// single map; an empty map is emitted when none are configured.
#[allow(clippy::too_many_arguments)]
fn render_mcp_servers_config(
    configs: BuiltinMcpConfigs<'_>,
    base_url: &str,
    proxy_token: &str,
    memory_proxy_token: &str,
    recorder_proxy_token: &str,
    _routine_browser_proxy_token: &str,
    connector_proxy_token: &str,
    computer_use_proxy_token: &str,
    obsidian_proxy_token: &str,
) -> String {
    let mut entries = String::new();
    if let Some(config) = configs.context {
        entries.push_str(&render_context_mcp_entry(
            config,
            base_url,
            memory_proxy_token,
        ));
    }
    if let Some(config) = configs.web {
        entries.push_str(&render_web_mcp_entry(config, base_url, proxy_token));
    }
    if let Some(config) = configs.obsidian {
        entries.push_str(&render_obsidian_mcp_entry(
            config,
            base_url,
            obsidian_proxy_token,
        ));
    }
    if let Some(config) = configs.image {
        entries.push_str(&render_image_mcp_entry(config, base_url, proxy_token));
    }
    if let Some(config) = configs.video {
        entries.push_str(&render_video_mcp_entry(config, base_url, proxy_token));
    }
    if let Some(config) = configs.recorder {
        entries.push_str(&render_recorder_mcp_entry(
            config,
            base_url,
            recorder_proxy_token,
        ));
    }
    if let Some(config) = configs.browser {
        entries.push_str(&render_browser_mcp_entry(config, base_url));
        for grant in config.routine_grants.iter().filter(|grant| grant.enabled) {
            entries.push_str(&render_routine_browser_mcp_entry(config, base_url, grant));
        }
    }
    if let Some(config) = configs.computer_use {
        entries.push_str(&render_computer_use_mcp_entry(
            config,
            base_url,
            computer_use_proxy_token,
        ));
    }
    // Read connector servers get the read timeout; action servers get a longer
    // one because a mutating call can park on the user's approval.
    if let Some(config) = configs.gmail {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_GMAIL_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            30,
        ));
    }
    if let Some(config) = configs.gmail_actions {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_GMAIL_ACTIONS_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            JUNE_CONNECTOR_ACTIONS_TOOL_TIMEOUT_SECS,
        ));
    }
    if let Some(config) = configs.gcal {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_GCAL_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            30,
        ));
    }
    if let Some(config) = configs.gcal_actions {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_GCAL_ACTIONS_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            JUNE_CONNECTOR_ACTIONS_TOOL_TIMEOUT_SECS,
        ));
    }
    if let Some(config) = configs.linear {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_LINEAR_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            30,
        ));
    }
    if let Some(config) = configs.linear_actions {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_LINEAR_ACTIONS_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            JUNE_CONNECTOR_ACTIONS_TOOL_TIMEOUT_SECS,
        ));
    }
    if let Some(config) = configs.notion {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_NOTION_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            60,
        ));
    }
    if let Some(config) = configs.notion_actions {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_NOTION_ACTIONS_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            JUNE_CONNECTOR_ACTIONS_TOOL_TIMEOUT_SECS,
        ));
    }
    if let Some(config) = configs.github {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_GITHUB_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            30,
        ));
    }
    if let Some(config) = configs.github_actions {
        entries.push_str(&render_connector_mcp_entry(
            JUNE_GITHUB_ACTIONS_MCP_SERVER_NAME,
            config,
            base_url,
            connector_proxy_token,
            JUNE_CONNECTOR_ACTIONS_TOOL_TIMEOUT_SECS,
        ));
    }
    // Per-job earned-autonomy servers: same action script, but with a grant
    // token and a tools.include filter so only the granted tools run without
    // parking.
    for config in configs.connector_autos {
        entries.push_str(&render_connector_auto_mcp_entry(
            config,
            base_url,
            connector_proxy_token,
        ));
    }
    if entries.is_empty() {
        return "mcp_servers: {}\n".to_string();
    }
    format!("mcp_servers:\n{entries}")
}

fn render_context_mcp_entry(
    config: &JuneContextMcpConfig,
    base_url: &str,
    memory_proxy_token: &str,
) -> String {
    format!(
        r#"  {server_name}:
    enabled: true
    command: {command}
    args:
      - {script_path}
      - {database_path}
      - {memory_settings_path}
      - {active_profile_path}
      - {base_url}
    env:
      PYTHONUNBUFFERED: "1"
      {token_env}: {token}
    timeout: 30
    connect_timeout: 10
"#,
        server_name = JUNE_CONTEXT_MCP_SERVER_NAME,
        command = yaml_string(&config.command),
        script_path = yaml_string(&config.script_path.to_string_lossy()),
        database_path = yaml_string(&config.database_path.to_string_lossy()),
        memory_settings_path = yaml_string(&config.memory_settings_path.to_string_lossy()),
        active_profile_path = yaml_string(&config.active_profile_path.to_string_lossy()),
        base_url = yaml_string(base_url),
        token_env = JUNE_MEMORY_MCP_TOKEN_ENV,
        token = yaml_string(memory_proxy_token),
    )
}

