    #[test]
    fn memory_off_repairs_missing_or_corrupt_config_fail_closed() {
        let missing_home = tempfile::tempdir().expect("missing tempdir");
        let missing = missing_home.path().join("config.yaml");
        update_hermes_memory_policy_file(&missing, false).expect("repair missing config");
        let repaired: serde_yaml::Value = serde_yaml::from_str(
            &std::fs::read_to_string(&missing).expect("read repaired missing config"),
        )
        .expect("missing replacement parses");
        assert_eq!(repaired["agent"]["disabled_toolsets"][0], "memory");

        let corrupt_home = tempfile::tempdir().expect("corrupt tempdir");
        let corrupt = corrupt_home.path().join("config.yaml");
        let original = b": invalid yaml: [";
        std::fs::write(&corrupt, original).expect("seed corrupt config");
        update_hermes_memory_policy_file(&corrupt, false).expect("repair corrupt config");
        let repaired: serde_yaml::Value = serde_yaml::from_str(
            &std::fs::read_to_string(&corrupt).expect("read repaired corrupt config"),
        )
        .expect("corrupt replacement parses");
        assert_eq!(repaired["agent"]["disabled_toolsets"][0], "memory");

        let entries: Vec<PathBuf> = std::fs::read_dir(corrupt_home.path())
            .expect("read config directory")
            .map(|entry| entry.expect("directory entry").path())
            .collect();
        let backup = entries
            .iter()
            .find(|path| {
                path.file_name()
                    .and_then(|name| name.to_str())
                    .is_some_and(|name| {
                        name.starts_with(HERMES_CONFIG_CORRUPT_BACKUP_PREFIX)
                            && name.ends_with(".bak")
                    })
            })
            .expect("corrupt backup");
        assert_eq!(std::fs::read(backup).expect("read backup"), original);
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            assert_eq!(
                std::fs::metadata(backup)
                    .expect("backup metadata")
                    .permissions()
                    .mode()
                    & 0o777,
                0o600,
            );
        }
        assert!(!entries.iter().any(|path| {
            path.file_name()
                .and_then(|name| name.to_str())
                .is_some_and(|name| name.starts_with(HERMES_CONFIG_ATOMIC_TEMP_PREFIX))
        }));
    }

    #[test]
    fn merge_hermes_config_prunes_stale_connector_servers() {
        let home = tempfile::tempdir().expect("tempdir");
        let config_path = home.path().join("config.yaml");
        // A prior spawn had a connected Google account and an autonomous
        // routine, so config.yaml carries June's connector servers and a
        // per-job auto server, next to a user-added server and June's context.
        std::fs::write(
            &config_path,
            r#"mcp_servers:
  june_context:
    command: "/old/python"
  june_gmail:
    command: "/old/python"
  june_gmail_actions:
    command: "/old/python"
  june_gcal:
    command: "/old/python"
  june_gcal_auto_ab12cd34:
    command: "/old/python"
  june_linear:
    command: "/old/python"
  june_linear_actions:
    command: "/old/python"
  todoist:
    url: "https://ai.todoist.net/mcp"
"#,
        )
        .expect("seed config");

        // The account is now disconnected: the render carries no connectors.
        let rendered = render_hermes_config(
            "m",
            false,
            "http://127.0.0.1:9/v1",
            "t",
            "memory",
            "recorder",
            "browser",
            "connector",
            "computer-use",
            "obsidian",
            "web",
            &[],
            BuiltinMcpConfigs {
                context: Some(&test_june_context_mcp_config()),
                web: None,
                obsidian: None,
                image: None,
                video: None,
                recorder: None,
                computer_use: None,
                gmail: None,
                gmail_actions: None,
                gcal: None,
                gcal_actions: None,
                linear: None,
                linear_actions: None,
                notion: None,
                notion_actions: None,
                github: None,
                github_actions: None,
                connector_autos: &[],
                browser: None,
            },
        );
        let merged = merge_hermes_config(&config_path, &rendered);
        let value: serde_yaml::Value = serde_yaml::from_str(&merged).expect("merged parses");

        // Every stale June connector entry (base, actions, per-job auto,
        // Linear read and actions) is gone.
        assert!(value["mcp_servers"]["june_gmail"].is_null());
        assert!(value["mcp_servers"]["june_gmail_actions"].is_null());
        assert!(value["mcp_servers"]["june_gcal"].is_null());
        assert!(value["mcp_servers"]["june_gcal_auto_ab12cd34"].is_null());
        assert!(value["mcp_servers"]["june_linear"].is_null());
        assert!(value["mcp_servers"]["june_linear_actions"].is_null());
        // The user server and June's always-rendered context server survive.
        assert_eq!(
            value["mcp_servers"]["todoist"]["url"],
            "https://ai.todoist.net/mcp"
        );
        assert!(!value["mcp_servers"]["june_context"].is_null());
    }

    #[test]
    fn effective_external_skill_dirs_reads_existing_config_defensively() {
        let home = tempfile::tempdir().expect("tempdir");
        let default = home.path().join("default-skills");
        let custom = home.path().join("team-skills");
        let string_config = home.path().join("string.yaml");
        std::fs::write(
            &string_config,
            format!(
                "skills:\n  external_dirs: {}\n",
                yaml_string(&custom.to_string_lossy())
            ),
        )
        .expect("seed string config");

        assert_eq!(
            effective_external_skill_dirs_from_config(
                &string_config,
                std::slice::from_ref(&default)
            ),
            vec![default.clone(), custom.clone()]
        );

        let list_config = home.path().join("list.yaml");
        std::fs::write(
            &list_config,
            format!(
                r#"skills:
  external_dirs:
    - {}
    - 42
    - ""
    - {}
    - {}
"#,
                yaml_string(&custom.to_string_lossy()),
                yaml_string(&default.to_string_lossy()),
                yaml_string(&home.path().join("more-skills").to_string_lossy()),
            ),
        )
        .expect("seed list config");

        assert_eq!(
            effective_external_skill_dirs_from_config(&list_config, std::slice::from_ref(&default)),
            vec![default.clone(), custom, home.path().join("more-skills"),]
        );

        let bad_config = home.path().join("bad.yaml");
        std::fs::write(&bad_config, ": not yaml : [").expect("seed bad config");
        assert_eq!(
            effective_external_skill_dirs_from_config(&bad_config, std::slice::from_ref(&default)),
            vec![default]
        );
    }

